var ctrl, speed, amount, k, N, starIndex, step, on, i, on, phase, bump;
ctrl = thisComp.layer('TWINKLE_CTRL');
speed = ctrl.effect('Twinkle Speed')('Slider');
amount = ctrl.effect('Twinkle Amount')('Slider');
k = Math.round(ctrl.effect('Twinkles At Once')('Slider'));
N = $bm_sub(thisComp.numLayers, 1);
starIndex = $bm_sub(index, 1);
step = Math.floor($bm_mul(time, speed));
seedRandom(step, true);
on = false;
for (i = 0; i < k; i++) {
    if (starIndex == Math.floor(random(1, N + 1)))
        on = true;
}
if (!on) {
    $bm_rt = 0;
} else {
    phase = $bm_mod($bm_mul(time, speed), 1);
    bump = Math.sin($bm_mul(phase, Math.PI));
    $bm_rt = $bm_mul(bump, 180);
}

s.x:
var $bm_rt;
var ctrl, speed, amt, rand, kBase, wanderMax, wanderRate, wanderStep, target, tt, w, k, N, starIndex, k, t, step, p, on, base, phase, bump, low, high, amp, s;
ctrl = thisComp.layer('TWINKLE_CTRL');
speed = ctrl.effect('Twinkle Speed')('Slider');
amt = ctrl.effect('Twinkle Amount')('Slider');
rand = $bm_div(ctrl.effect('Randomness')('Slider'), 100);
kBase = Math.round(ctrl.effect('Stars On (Count)')('Slider'));
wanderMax = ctrl.effect('Count Wander')('Slider');
wanderRate = 0.08;
wanderStep = Math.floor($bm_mul(time, wanderRate));
seedRandom($bm_sum(9999, wanderStep), true);
target = $bm_mul(random() < 0.5 ? -1 : 1, random(1, $bm_sum(wanderMax, 1)));
tt = $bm_mod($bm_mul(time, wanderRate), 1);
w = ease(tt, 0, 1, 0, target);
k = Math.round($bm_sum(kBase, w));
N = $bm_sub(thisComp.numLayers, 1);
starIndex = $bm_sub(index, 1);
k = Math.max(0, Math.min(k, N));
t = $bm_mul(time, speed);
step = Math.floor($bm_sum(t, $bm_mul(rand, 2)));
seedRandom($bm_sum($bm_mul(step, 10000), starIndex), true);
p = N > 0 ? $bm_div(k, N) : 0;
on = random() < p;
$bm_rt = base = value[0];
if (!on) {
    $bm_rt = [
        base,
        base
    ];
} else {
    phase = $bm_mod($bm_sum(t, random(0, rand)), 1);
    bump = Math.sin($bm_mul(phase, Math.PI));
    low = linear(rand, 0, 1, 0.85, 0.25);
    high = linear(rand, 0, 1, 1, 1.35);
    amp = random($bm_mul(amt, low), $bm_mul(amt, high));
    s = $bm_sum(base, $bm_mul(bump, amp));
    $bm_rt = [
        s,
        s
    ];
}

